import os
from flask import Flask, request, jsonify
from pymongo import MongoClient
from bson.objectid import ObjectId
from datetime import datetime

app = Flask(__name__)

# MongoDB connection
client = MongoClient('mongodb://localhost:27017/')
db = client.cms_db # Database name

# Collections
users_collection = db.users
documents_collection = db.documents

# Ensure indexes for frequently queried fields
users_collection.create_index("username", unique=True)
documents_collection.create_index("author_id")
documents_collection.create_index("title")
documents_collection.create_index("category")
documents_collection.create_index("tags")
documents_collection.create_index("published_date")


# --- User Profile Management ---

@app.route('/users', methods=['POST'])
def create_user():
    data = request.get_json()
    if not data or not data.get('username') or not data.get('email'):
        return jsonify({"error": "Username and email are required"}), 400

    user_data = {
        "username": data['username'],
        "email": data['email'],
        "full_name": data.get('full_name'),
        "bio": data.get('bio'),
        "created_at": datetime.utcnow()
    }
    try:
        result = users_collection.insert_one(user_data)
        new_user = users_collection.find_one({"_id": result.inserted_id})
        new_user['_id'] = str(new_user['_id'])
        return jsonify(new_user), 201
    except Exception as e:
        return jsonify({"error": str(e)}), 400

@app.route('/users/<string:user_id>', methods=['GET'])
def get_user(user_id):
    try:
        user = users_collection.find_one({"_id": ObjectId(user_id)})
        if user:
            user['_id'] = str(user['_id'])
            return jsonify(user), 200
        return jsonify({"error": "User not found"}), 404
    except Exception as e:
        return jsonify({"error": "Invalid User ID format"}), 400

@app.route('/users/<string:user_id>', methods=['PUT'])
def update_user(user_id):
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data provided for update"}), 400

    update_fields = {k: v for k, v in data.items() if k not in ['_id', 'username', 'created_at']}
    
    try:
        result = users_collection.update_one({"_id": ObjectId(user_id)}, {"$set": update_fields})
        if result.matched_count == 0:
            return jsonify({"error": "User not found"}), 404
        
        updated_user = users_collection.find_one({"_id": ObjectId(user_id)})
        updated_user['_id'] = str(updated_user['_id'])
        return jsonify(updated_user), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 400

@app.route('/users/<string:user_id>', methods=['DELETE'])
def delete_user(user_id):
    try:
        result = users_collection.delete_one({"_id": ObjectId(user_id)})
        if result.deleted_count == 0:
            return jsonify({"error": "User not found"}), 404
        return jsonify({"message": "User deleted successfully"}), 200
    except Exception as e:
        return jsonify({"error": "Invalid User ID format"}), 400

# --- Document Management ---

@app.route('/documents', methods=['POST'])
def create_document():
    data = request.get_json()
    required_fields = ['title', 'content', 'author_id', 'category']
    if not all(field in data for field in required_fields):
        return jsonify({"error": f"Missing required fields: {', '.join(required_fields)}"}), 400
    
    # Check if author_id exists
    try:
        if not users_collection.find_one({"_id": ObjectId(data['author_id'])}):
            return jsonify({"error": "Author not found"}), 404
    except Exception:
        return jsonify({"error": "Invalid author_id format"}), 400

    document_data = {
        "title": data['title'],
        "content": data['content'],
        "author_id": ObjectId(data['author_id']),
        "category": data['category'],
        "tags": data.get('tags', []), # List of strings
        "status": data.get('status', 'draft'), # e.g., 'draft', 'published', 'archived'
        "published_date": datetime.utcnow() if data.get('status') == 'published' else None,
        "created_at": datetime.utcnow(),
        "updated_at": datetime.utcnow()
    }
    
    try:
        result = documents_collection.insert_one(document_data)
        new_doc = documents_collection.find_one({"_id": result.inserted_id})
        new_doc['_id'] = str(new_doc['_id'])
        new_doc['author_id'] = str(new_doc['author_id'])
        return jsonify(new_doc), 201
    except Exception as e:
        return jsonify({"error": str(e)}), 400

@app.route('/documents/<string:doc_id>', methods=['GET'])
def get_document(doc_id):
    try:
        document = documents_collection.find_one({"_id": ObjectId(doc_id)})
        if document:
            document['_id'] = str(document['_id'])
            document['author_id'] = str(document['author_id'])
            return jsonify(document), 200
        return jsonify({"error": "Document not found"}), 404
    except Exception as e:
        return jsonify({"error": "Invalid Document ID format"}), 400

@app.route('/documents/<string:doc_id>', methods=['PUT'])
def update_document(doc_id):
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data provided for update"}), 400

    update_fields = {k: v for k, v in data.items() if k not in ['_id', 'author_id', 'created_at']}
    update_fields['updated_at'] = datetime.utcnow()

    # Handle 'published_date' if status changes to 'published'
    if 'status' in update_fields and update_fields['status'] == 'published':
        # Only set if it's not already set or if it's explicitly set to published now
        current_doc = documents_collection.find_one({"_id": ObjectId(doc_id)})
        if current_doc and current_doc.get('status') != 'published':
            update_fields['published_date'] = datetime.utcnow()
    elif 'status' in update_fields and update_fields['status'] != 'published':
        update_fields['published_date'] = None # Clear if no longer published

    try:
        result = documents_collection.update_one({"_id": ObjectId(doc_id)}, {"$set": update_fields})
        if result.matched_count == 0:
            return jsonify({"error": "Document not found"}), 404
        
        updated_doc = documents_collection.find_one({"_id": ObjectId(doc_id)})
        updated_doc['_id'] = str(updated_doc['_id'])
        updated_doc['author_id'] = str(updated_doc['author_id'])
        return jsonify(updated_doc), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 400

@app.route('/documents/<string:doc_id>', methods=['DELETE'])
def delete_document(doc_id):
    try:
        result = documents_collection.delete_one({"_id": ObjectId(doc_id)})
        if result.deleted_count == 0:
            return jsonify({"error": "Document not found"}), 404
        return jsonify({"message": "Document deleted successfully"}), 200
    except Exception as e:
        return jsonify({"error": "Invalid Document ID format"}), 400

# --- Document Queries ---

@app.route('/documents/search', methods=['GET'])
def search_documents():
    query_params = request.args
    filter_query = {}

    if 'title' in query_params:
        filter_query['title'] = {'$regex': query_params['title'], '$options': 'i'} # Case-insensitive search
    if 'category' in query_params:
        filter_query['category'] = query_params['category']
    if 'tags' in query_params:
        filter_query['tags'] = {'$in': query_params['tags'].split(',')} # Comma-separated tags
    if 'author_id' in query_params:
        try:
            filter_query['author_id'] = ObjectId(query_params['author_id'])
        except Exception:
            return jsonify({"error": "Invalid author_id format"}), 400
    if 'status' in query_params:
        filter_query['status'] = query_params['status']
    if 'published_after' in query_params:
        try:
            date_obj = datetime.fromisoformat(query_params['published_after'].replace('Z', '+00:00'))
            filter_query['published_date'] = {'$gte': date_obj}
        except ValueError:
            return jsonify({"error": "Invalid published_after date format. Use ISO 8601 (e.g., YYYY-MM-DDTHH:MM:SSZ)"}), 400
    if 'published_before' in query_params:
        try:
            date_obj = datetime.fromisoformat(query_params['published_before'].replace('Z', '+00:00'))
            if 'published_date' in filter_query:
                filter_query['published_date']['$lte'] = date_obj
            else:
                filter_query['published_date'] = {'$lte': date_obj}
        except ValueError:
            return jsonify({"error": "Invalid published_before date format. Use ISO 8601 (e.g., YYYY-MM-DDTHH:MM:SSZ)"}), 400


    # Pagination
    page = int(query_params.get('page', 1))
    per_page = int(query_params.get('per_page', 10))
    skip = (page - 1) * per_page

    documents = []
    # Sort by published_date descending by default, or updated_at if not published
    sort_by = [("published_date", -1), ("updated_at", -1)] 
    
    cursor = documents_collection.find(filter_query).sort(sort_by).skip(skip).limit(per_page)
    
    for doc in cursor:
        doc['_id'] = str(doc['_id'])
        doc['author_id'] = str(doc['author_id'])
        documents.append(doc)
    
    total_docs = documents_collection.count_documents(filter_query)

    return jsonify({
        "total_results": total_docs,
        "page": page,
        "per_page": per_page,
        "documents": documents
    }), 200

# --- Aggregation Pipelines ---

@app.route('/reports/documents_per_author', methods=['GET'])
def documents_per_author():
    pipeline = [
        {
            "$group": {
                "_id": "$author_id",
                "total_documents": {"$sum": 1},
                "published_documents": {
                    "$sum": {
                        "$cond": [{"$eq": ["$status", "published"]}, 1, 0]
                    }
                }
            }
        },
        {
            "$lookup": {
                "from": "users",
                "localField": "_id",
                "foreignField": "_id",
                "as": "author_info"
            }
        },
        {
            "$unwind": "$author_info"
        },
        {
            "$project": {
                "_id": 0,
                "author_id": {"$toString": "$_id"},
                "username": "$author_info.username",
                "full_name": "$author_info.full_name",
                "total_documents": 1,
                "published_documents": 1
            }
        },
        {
            "$sort": {"total_documents": -1}
        }
    ]
    
    result = list(documents_collection.aggregate(pipeline))
    return jsonify(result), 200

@app.route('/reports/documents_by_category', methods=['GET'])
def documents_by_category():
    pipeline = [
        {
            "$group": {
                "_id": "$category",
                "total_documents": {"$sum": 1},
                "published_documents": {
                    "$sum": {
                        "$cond": [{"$eq": ["$status", "published"]}, 1, 0]
                    }
                },
                "average_document_length": {
                    "$avg": {"$strLenCP": "$content"} # Use $strLenCP for character count
                }
            }
        },
        {
            "$sort": {"total_documents": -1}
        }
    ]
    
    result = list(documents_collection.aggregate(pipeline))
    return jsonify(result), 200

@app.route('/reports/top_tags', methods=['GET'])
def top_tags():
    limit = int(request.args.get('limit', 10))
    pipeline = [
        {"$unwind": "$tags"},
        {
            "$group": {
                "_id": "$tags",
                "count": {"$sum": 1}
            }
        },
        {"$sort": {"count": -1}},
        {"$limit": limit}
    ]
    
    result = list(documents_collection.aggregate(pipeline))
    return jsonify(result), 200

@app.route('/reports/monthly_published_documents', methods=['GET'])
def monthly_published_documents():
    pipeline = [
        {"$match": {"status": "published", "published_date": {"$ne": None}}},
        {
            "$group": {
                "_id": {
                    "year": {"$year": "$published_date"},
                    "month": {"$month": "$published_date"}
                },
                "count": {"$sum": 1}
            }
        },
        {"$sort": {"_id.year": 1, "_id.month": 1}},
        {
            "$project": {
                "_id": 0,
                "year": "$_id.year",
                "month": "$_id.month",
                "count": 1
            }
        }
    ]
    
    result = list(documents_collection.aggregate(pipeline))
    return jsonify(result), 200


if __name__ == '__main__':
    # Run Flask app
    app.run(debug=True, port=5000)